<template>
    <CommonList
        selection-type="radio"
        row-key="id"
        :has-more-search="true"
        :auto-load="true"
        ref="listRef"
        cell-overflow="ellipsis"
        @selection-change="handleSelectionChange"
        @current-row-change="handleCurrentRowChange"
        @load-start="handleLoadList"
        @search-click="handleLoadList"
        @pagination-change="handleLoadList"
        @reset-click="handleReset"
    >
        <template #search-item-fixed>
            <div class="common-search-item">
                <label class="common-search-label80">流水号：</label>
                <el-input v-model="searchForm.serialNo" class="common-input150" placeholder="请输入"></el-input>
            </div>
            <div class="common-search-item">
                <label class="common-search-label80">收支：</label>
                <el-select  v-model="searchForm.inoutType" class="common-input120" placeholder="请选择">
                    <el-option  v-for="item in Options.inoutType"
                                :key="item.enumCodeName+item.code"
                                :label="item.enumCodeName"
                                :value="item.code"
                    ></el-option>
                </el-select>
            </div>
            <div class="common-search-item">
                <label class="common-search-label80">账单类型：</label>
                <el-select v-model="searchForm.billType" class="common-input150" placeholder="请选择" clearable>
                    <el-option label="废品账单" value="waste"></el-option>
                    <el-option v-for="item in Options.billTypeOptions"
                                :key="item.code"
                                :label="item.label"
                                :value="item.code"
                    ></el-option>
                </el-select>
            </div>
            <div class="common-search-item">
                <label class="common-search-label80">收/支方：</label>
                <el-select
                    v-model="searchForm.cstId"
                    class="common-input150"
                    placeholder="请选择"
                    ref="cstSelectRef"
                    filterable
                    remote
                    :remote-method="(val) => getCstSelect(val, false)"
                    @visible-change="handleSelectVisibleChange"
                    @click="(val) => getCstSelect(val, false)"
                >
                    <el-option
                        v-for="item in Options.allCst?.cstList"
                        :key="item.cstId"
                        :label="item.cstName"
                        :value="item.cstId"
                    >{{ item.cstPhone }} {{ item.cstName }}</el-option>
                </el-select>
            </div>
        </template>

        <template #search-item-expand>
            <div class="common-search-item">
                <label class="common-search-label80">金额范围：</label>
                <div style="display: flex; align-items: center; gap: 8px;">
                    <el-input
                        v-model="searchForm.minAmount"
                        placeholder="最小金额"
                        class="common-input100"
                        type="text"
                    ></el-input>
                    <span class="amount-separator">-</span>
                    <el-input
                        v-model="searchForm.maxAmount"
                        placeholder="最大金额"
                        class="common-input100"
                        type="text"
                    ></el-input>
                </div>
            </div>
            <div class="common-search-item">
                <label class="common-search-label80">日期：</label>
                <el-date-picker
                    v-model="searchForm.dateRange"
                    type="datetimerange"
                    range-separator="至"
                    start-placeholder="开始日期"
                    end-placeholder="结束日期"
                    format="YYYY-MM-DD HH:mm:ss"
                    value-format="YYYY-MM-DD HH:mm:ss"
                    class="common-input400"
                ></el-date-picker>
            </div>
        </template>

        <template #btn-group>
            <el-button type="primary" class="list-btn" @click="handleAdd">
                <el-icon><Plus/></el-icon>
                新增废品账单
            </el-button>
            <el-button type="success" class="list-btn" @click="handleAddOther">
                <el-icon><Plus/></el-icon>
                新增其他账单
            </el-button>
            <el-button
                type="warning"
                class="list-btn"
                @click="handleEdit"
                :disabled="!listShow"
            >
                <el-icon><Edit/></el-icon>
                修改
            </el-button>
            <el-button
        type="danger"
        class="list-btn"
        @click="handleDelete"
        :disabled="!oneShow || oneShow.status !== '0'"
      >
        <el-icon><Delete/></el-icon>
        删除
      </el-button>
        </template>

        <template #table-column>
            <el-table-column prop="serialNo" label="流水号" align="center" min-width="180"></el-table-column>
            <el-table-column prop="billType" label="账单类型" align="center" min-width="120">
                <template #default="scope">
                    {{ getBillTypeName(scope.row.billType) }}
                </template>
            </el-table-column>
            <el-table-column prop="usageQuantity" label="使用量" align="center" min-width="100">
                <template #default="scope">
                    <span v-if="scope.row.usageQuantity !== null && scope.row.usageQuantity !== undefined">
                        {{ scope.row.usageQuantity }}
                        <span v-if="scope.row.billType === 'electricity'">度</span>
                        <span v-if="scope.row.billType === 'water'">吨</span>
                    </span>
                    <span v-else>-</span>
                </template>
            </el-table-column>
            <el-table-column prop="amount" label="金额（元）" align="center" min-width="120">
                <template #default="scope">
                    {{ scope.row.amount?.toFixed(2) || '0.00' }}
                </template>
            </el-table-column>
            <el-table-column prop="totalWeight" label="总重量(kg)" align="center" min-width="120">
                <template #default="scope">
                    <span v-if="scope.row.billType === 'waste' || !scope.row.billType">{{ scope.row.totalWeight }}</span>
                    <span v-else>-</span>
                </template>
            </el-table-column>
            <el-table-column prop="status" label="状态" align="center" min-width="100">
                <template #default="scope">
                    {{ Options.statusOptions.find(item => item.code === scope.row.status)?.label || '' }}
                </template>
            </el-table-column>
            <el-table-column prop="myCstName" label="公司" align="center" min-width="180"></el-table-column>
            <el-table-column prop="inoutType" label="收入/支出" align="center" min-width="120">
                <template #default="scope">
                    {{ Options.inoutType.find(item => item.code === scope.row.inoutType)?.enumCodeName || '' }}
                </template>
            </el-table-column>
            <el-table-column prop="cstName" label="客户" align="center" min-width="180"></el-table-column>
            <el-table-column prop="remark" label="备注" align="center" min-width="180" ></el-table-column>
            <el-table-column prop="serialDate" label="日期" align="center" min-width="180" :resizable="false">
                <template #default="scope">
                    {{ $formatTime(scope.row.serialDate) }}
                </template>
            </el-table-column>
        </template>

        <template #extra>
            <el-dialog
                v-model="dialogVisible"
                :title="getDialogTitle()"
                width="700px"
                destroy-on-close
            >
                <el-form
                    ref="formRef"
                    :model="formData"
                    :rules="formRules"
                    label-width="120px"
                    class="list-modal-form"
                >
                    <el-form-item label="流水号" prop="serialNo" v-if="dialogType === 'edit'">
                        <el-input
                            v-model="formData.serialNo"
                            placeholder="系统生成"
                            style="width: 100%;"
                            readonly disabled
                        ></el-input>
                    </el-form-item>

                    <el-form-item label="公司" prop="myCstId">
                        <el-select
                            v-model="formData.myCstId"
                            style="width: 100%;"
                            placeholder="请选择本公司"
                            :disabled="dialogType === 'edit' && (formData.status === '1' || formData.status === '2')"
                            @change="(val) => {
                                const company = Options.userCompanyList.find(c => c.companyId === val)
                                handleCompanyChange(val, company ? company.companyName : '')
                            }"
                        >
                            <el-option
                                v-for="item in Options.userCompanyList"
                                :key="item.companyId"
                                :label="item.companyName"
                                :value="item.companyId"
                            ></el-option>
                        </el-select>
                    </el-form-item>
                    <el-form-item label="客户" prop="cstId">
                        <el-select
                            v-model="formData.cstId"
                            value-key="cstId"
                            style="width: 100%;"
                            placeholder="请选择"
                            ref="cstSelectRef"
                            filterable
                            remote
                            :remote-method="(val) => getCstSelect(val, false)"
                            @click="(val) => getCstSelect(val, false)"
                            :disabled="dialogType === 'edit' && (formData.status === '1' || formData.status === '2')"
                            @change="(val) => {
                                const cst = Options.allCst.cstList.find(c => c.cstId === val)
                                formData.cstName = cst ? cst.cstName : ''
                                formData.cstPhone = cst ? cst.cstPhone : ''
                            }"
                        >
                            <el-option
                                v-for="item in Options.allCst?.cstList"
                                :key="item.cstId"
                                :label="item.cstName"
                                :value="item.cstId"
                            >{{ item.cstPhone }} {{ item.cstName }}</el-option>
                        </el-select>
                    </el-form-item>
                    <el-form-item label="收支类型" prop="inoutType">
                        <el-select
                            v-model="formData.inoutType"
                            placeholder="请选择收支类型"
                            style="width: 100%;"
                            :disabled="dialogType === 'edit' && (formData.status === '1' || formData.status === '2')"
                        >
                            <el-option  v-for="item in Options.inoutType"
                                        :key="item.enumCodeName+item.code"
                                        :label="item.enumCodeName"
                                        :value="item.code"
                            ></el-option>
                        </el-select>
                    </el-form-item>
                    <el-form-item label="账单类型" prop="billType" v-if="!isWasteMode">
                        <el-select
                            v-model="formData.billType"
                            placeholder="请选择账单类型"
                            style="width: 100%;"
                            :disabled="dialogType === 'edit' && (formData.status === '1' || formData.status === '2')"
                        >
                            <el-option
                                v-for="item in Options.billTypeOptions"
                                :key="item.code"
                                :label="item.label"
                                :value="item.code"
                            ></el-option>
                        </el-select>
                    </el-form-item>
                    <el-form-item
                        v-if="!isWasteMode && currentBillType?.needUsage"
                        :label="`使用量（${currentBillType?.unit}）`"
                        prop="usageQuantity"
                    >
                        <el-input-number
                            v-model="formData.usageQuantity"
                            :min="0"
                            :precision="2"
                            :step="1"
                            style="width: 100%;"
                            placeholder="请输入使用量"
                            :disabled="dialogType === 'edit' && (formData.status === '1' || formData.status === '2')"
                        ></el-input-number>
                    </el-form-item>
                    <template v-if="isWasteMode">
                        <el-form-item label="物品">
                            <el-checkbox-group v-model="checkedItemIds" @change="handleItemCheckChange" :disabled="dialogType === 'edit' && (formData.status === '1' || formData.status === '2')">
                                <el-checkbox
                                    v-for="item in Options.recycleItemList"
                                    :key="item.itemId"
                                    :label="item.itemId"
                                >{{ item.itemName }} ({{ item.price }}元/kg)</el-checkbox>
                            </el-checkbox-group>
                        </el-form-item>
                        <div v-if="formData.itemList.length > 0" style="margin-bottom: 18px;">
                            <el-divider>物品明细</el-divider>
                            <el-table :data="formData.itemList" border style="width: 100%;">
                                <el-table-column prop="itemName" label="物品名称" width="180" :resizable="false"></el-table-column>
                                <el-table-column prop="price" label="单价(元)" width="160" :resizable="false">
                                    <template #default="{ row }">
                                        <el-input-number
                                            v-model="row.price"
                                            :min="0"
                                            :precision="2"
                                            :step="0.1"
                                            style="width: 100%;"
                                            @change="calculateTotalAmount"
                                            :disabled="!(formData.inoutType === '1') || (dialogType === 'edit' && (formData.status === '1' || formData.status === '2'))"
                                        ></el-input-number>
                                    </template>
                                </el-table-column>
                                <el-table-column label="重量(kg)" width="160" :resizable="false">
                                    <template #default="{ row }">
                                        <el-input-number
                                            v-model="row.weight"
                                            :min="0"
                                            :precision="2"
                                            :step="1"
                                            style="width: 100%;"
                                            @change="calculateTotalAmount"
                                            :disabled="dialogType === 'edit' && (formData.status === '1' || formData.status === '2')"
                                        ></el-input-number>
                                    </template>
                                </el-table-column>
                                <el-table-column label="金额(元)" width="auto" :resizable="false">
                                    <template #default="{ row }">
                                        {{ row.amount || '0.00' }}
                                    </template>
                                </el-table-column>
                            </el-table>
                        </div>
                        <el-form-item label="总金额" prop="amount">
                            <el-input
                                v-model="formData.amount"
                                placeholder="系统自动计算"
                                style="width: 100%;"
                                readonly disabled
                            ></el-input>
                        </el-form-item>
                    </template>
                    <template v-else>
                        <el-form-item label="缴费金额" prop="amount">
                            <el-input-number
                                v-model="formData.amount"
                                :min="0"
                                :precision="2"
                                :step="0.01"
                                style="width: 100%;"
                                placeholder="请输入金额"
                                :disabled="dialogType === 'edit' && (formData.status === '1' || formData.status === '2')"
                            ></el-input-number>
                        </el-form-item>
                    </template>
                    <el-form-item label="状态" prop="status">
                        <el-radio-group v-model="formData.status" :disabled="dialogType === 'edit' && (formData.status === '1' || formData.status === '2')">
                            <el-radio
                                v-for="item in Options.statusOptions"
                                :key="item.code"
                                :value="item.code"
                            >{{ item.label }}</el-radio>
                        </el-radio-group>
                    </el-form-item>
                    <el-form-item label="备注" prop="remark">
                        <el-input
                            v-model="formData.remark"
                            type="textarea"
                            placeholder="请输入备注（选填）"
                            maxlength="250"
                            show-word-limit
                            :rows="3"
                            style="width: 100%;"
                            :disabled="dialogType === 'edit' && (formData.status === '1' || formData.status === '2')"
                        ></el-input>
                    </el-form-item>
                    <el-form-item label="日期" prop="serialDate">
                        <el-date-picker
                            v-model="formData.serialDate"
                            type="datetime"
                            placeholder="请选择日期时间"
                            format="YYYY-MM-DD HH:mm:ss"
                            value-format="YYYY-MM-DD HH:mm:ss"
                            style="width: 100%;"
                            :disabled="dialogType === 'edit' && (formData.status === '1' || formData.status === '2')"
                        ></el-date-picker>
                    </el-form-item>
                </el-form>
                <template #footer>
                    <div style="text-align: center; width: 100%;">
                        <el-button @click="dialogVisible = false">取消</el-button>
                        <el-button type="primary" @click="handleSubmit" :disabled="dialogType === 'edit' && (formData.status === '1' || formData.status === '2')">确定</el-button>
                    </div>
                </template>
            </el-dialog>
        </template>
    </CommonList>
</template>

<script setup>
    import useBillList from './wasteBillList.js'
    import { ref } from 'vue'

    const cstSelectRef = ref(null)

    const {
        searchForm,
        listRef,
        dialogType,
        formRef,
        oneShow,
        listShow,
        formData,
        formRules,
        Plus, Edit, Delete,
        handleSelectionChange,
        handleCurrentRowChange,
        handleAdd,
        handleAddOther,
        handleEdit,
        handleDelete,
        handleLoadList,
        handleReset,
        dialogVisible,
        Options,
        getCstSelect,
        checkedItemIds,
        handleItemCheckChange,
        calculateTotalAmount,
        handleSubmit,
        handleCompanyChange,
        isWasteMode,
        currentBillType
    } = useBillList()

    const getBillTypeName = (code) => {
        if (!code || code === 'waste') return '废品账单'
        const type = Options.value?.billTypeOptions.find(t => t.code === code)
        return type ? type.label : code
    }

    const getDialogTitle = () => {
        const prefix = dialogType.value === 'add' ? '新增' : '修改'
        const suffix = isWasteMode.value ? '废品账单' : '其他账单'
        return prefix + suffix
    }

    const handleSelectVisibleChange = (visible) => {
        Options.value?.allCst.handleSelectVisibleChange(visible, cstSelectRef, async () => {
            if (!Options.value.allCst.hasMore || Options.value.allCst.isLoading) return
            await getCstSelect(Options.value.allCst.currentQuery, true)
        })
    }
</script>
<style>
    @import '../../../assets/css/util/base-list.css';
</style>
