import { ref, reactive, onActivated, onMounted, nextTick, computed } from 'vue'
import { ElMessage, ElMessageBox } from 'element-plus'
import { MsgBox } from '@/util/msgutil/msgBox.js'
import { Plus, Edit, Delete } from '@element-plus/icons-vue'
import { request } from '@/util/globalContext'
import {  getDate, enumSelect, listCommon, useCstSelect } from '@/util/vueutil/commonList.js'

const BILL_TYPE_OPTIONS = [
    { code: 'water', label: '水费', unit: '吨', needUsage: true },
    { code: 'electricity', label: '电费', unit: '度', needUsage: true },
    { code: 'equipment', label: '设备杂费', unit: '', needUsage: false },
    { code: 'other', label: '其他', unit: '', needUsage: false }
]

export default function useBillList() {
    const listRef = ref(null)
    const dialogVisible = ref(false)
    const dialogType = ref('add')
    const formRef = ref(null)
    const billMode = ref('waste') // 'waste' 废品账单 | 'other' 其他账单

    const Options = ref({
        inoutType: [],
        statusOptions: [
            { code: '0', label: '待生效' },
            { code: '1', label: '未结算' },
            { code: '2', label: '已结算' }
        ],
        billTypeOptions: BILL_TYPE_OPTIONS,
        recycleItemList: [],
        userCompanyList: [],
        myCst: useCstSelect({ pageSize: 100 }),
        allCst: useCstSelect()
    })

    const searchForm = reactive({
        serialNo: '',
        inoutType: '',
        billType: '',
        dateRange: [],
        minAmount: '',
        maxAmount: '',
        cstId: ''
    })

    const {
        oneShow,
        listShow,
        handleReset,
        handleSelectionChange,
        handleCurrentRowChange
    } = listCommon(searchForm)

    const FORM_DEFAULT_WASTE = {
        id: '',
        serialNo: '',
        serialDate: '',
        inoutType: '0',
        amount: '',
        totalWeight: '',
        status: '0',
        remark: '',
        myCstId: '',
        myCstName: '',
        cstId: '',
        cstName: '',
        cstPhone: '',
        itemList: [],
        billType: 'waste'
    }

    const FORM_DEFAULT_OTHER = {
        id: '',
        serialNo: '',
        serialDate: '',
        inoutType: '0', // 默认支出 (0=支出, 1=收入)
        amount: '',
        usageQuantity: '',
        billType: 'water',
        status: '0',
        remark: '',
        myCstId: '',
        myCstName: '',
        cstId: '',
        cstName: '',
        cstPhone: ''
    }

    const formData = reactive({ ...FORM_DEFAULT_WASTE })

    const isWasteMode = computed(() => billMode.value === 'waste')

    const currentBillType = computed(() => {
        return Options.value.billTypeOptions.find(t => t.code === formData.billType)
    })



    const formRules = computed(() => {
        const rules = {
            myCstId: [
                { required: true, message: '请选择本公司', trigger: 'change' }
            ],
            cstId: [
                { required: true, message: '请选择客户', trigger: 'change' }
            ],
            inoutType: [
                { required: true, message: '请选择收支类型', trigger: 'change' }
            ],
            amount: [
                { required: true, message: '请输入金额', trigger: 'blur,change' }
            ],
            status: [
                { required: true, message: '请选择状态', trigger: 'change' }
            ],
            serialDate: [
                { required: true, message: '请选择日期时间', trigger: 'change' }
            ]
        }
        if (!isWasteMode.value && currentBillType.value?.needUsage) {
            rules.usageQuantity = [
                { required: true, message: `请输入使用量（${currentBillType.value.unit}）`, trigger: 'blur,change' }
            ]
        }
        if (dialogType.value === 'edit') {
            rules.serialNo = [
                { required: true, message: '流水号不能为空', trigger: 'change' }
            ]
        }
        return rules
    })

    const calculateTotalAmount = () => {
        let total = 0
        formData.itemList.forEach(item => {
            if (item.weight && item.price) {
                const amount = parseFloat(item.weight) * parseFloat(item.price)
                item.amount = amount.toFixed(2)
                total += amount
            }
        })
        formData.amount = total.toFixed(2)
    }

    const handleItemCheckChange = (checkedValues) => {
        const newItemList = []
        Options.value.recycleItemList.forEach(item => {
            if (checkedValues.includes(item.itemId)) {
                const existItem = formData.itemList.find(i => i.itemId === item.itemId)
                if (existItem) {
                    newItemList.push(existItem)
                } else {
                    newItemList.push({
                        itemId: item.itemId,
                        itemName: item.itemName,
                        price: item.price,
                        weight: '',
                        amount: ''
                    })
                }
            }
        })
        formData.itemList = newItemList
        calculateTotalAmount()
    }

    const checkedItemIds = computed(() => {
        return formData.itemList.map(item => item.itemId)
    })

    const loadRecycleItemsByCompany = async (companyId) => {
        try {
            const res = await request.get('/wasteBill/getRecycleItemList', { params: { companyId } })
            if (res.code === 200) {
                Options.value.recycleItemList = res.data || []
                // 如果是新增模式，才清空itemList；修改模式下不应该清空
                if (dialogType.value === 'add') {
                    formData.itemList = []
                    calculateTotalAmount()
                }
            }
        } catch (error) {
            ElMessage.error('加载物品列表失败：' + error)
        }
    }

    const handleCompanyChange = async (companyId, companyName) => {
        formData.myCstName = companyName || ''
        if (companyId && isWasteMode.value) {
            await loadRecycleItemsByCompany(companyId)
        } else {
            Options.value.recycleItemList = []
            if (dialogType.value === 'add' && isWasteMode.value) {
                formData.itemList = []
                calculateTotalAmount()
            }
        }
    }

    const handleLoadList = async (paginationParams) => {
        if (!listRef.value) return
        if (!listRef.value.isInited) {
            await nextTick()
            if (!listRef.value?.isInited) {
                ElMessage.warning('列表组件初始化中，请稍后重试')
                return
            }
        }

        listRef.value?.setLoading(true)
        try {
            const params = {
                ...paginationParams,
                startDate: searchForm.dateRange[0] || '',
                endDate: searchForm.dateRange[1] || '',
                minAmount: searchForm.minAmount || '',
                maxAmount: searchForm.maxAmount || '',
                serialNo: searchForm.serialNo,
                cstId: searchForm.cstId,
                inoutType: searchForm.inoutType,
                billType: searchForm.billType
            }
            const res = await request.get('/wasteBill/getPage', { params })
            if (listRef.value) {
                if (res.code === 200) {
                    listRef.value.updateListData(res.data.records || [])
                    listRef.value.updatePagination({
                        pageNum: paginationParams.pageNum,
                        pageSize: paginationParams.pageSize,
                        total: res.data.total || 0
                    })
                } else {
                    ElMessage.error('列表加载失败：' + (res.msg || '接口异常'))
                    listRef.value.updateListData([])
                    listRef.value.updatePagination({ ...paginationParams, total: 0 })
                }
            }
        } catch (error) {
            ElMessage.error('列表加载失败：网络异常')
            if (listRef.value) {
                listRef.value.updateListData([])
                listRef.value.updatePagination({ ...paginationParams, total: 0 })
            }
        } finally {
            listRef.value?.setLoading(false)
        }
    }

    const handleAdd = async () => {
        billMode.value = 'waste'
        dialogType.value = 'add'
        formRef.value?.resetFields()
        Object.assign(formData, JSON.parse(JSON.stringify(FORM_DEFAULT_WASTE)))
        formData.serialDate = await getDate('YYYY-MM-DD HH:mm:ss').catch(() => {})
        
        if (Options.value.userCompanyList && Options.value.userCompanyList.length > 0) {
            const mainCompany = Options.value.userCompanyList.find(c => c.isMain === '1') || Options.value.userCompanyList[0]
            formData.myCstId = mainCompany.companyId
            formData.myCstName = mainCompany.companyName
            await loadRecycleItemsByCompany(mainCompany.companyId)
        }
        
        dialogVisible.value = true
    }

    const handleAddOther = async () => {
        billMode.value = 'other'
        dialogType.value = 'add'
        formRef.value?.resetFields()
        Object.assign(formData, JSON.parse(JSON.stringify(FORM_DEFAULT_OTHER)))
        formData.serialDate = await getDate('YYYY-MM-DD HH:mm:ss').catch(() => {})
        
        if (Options.value.userCompanyList && Options.value.userCompanyList.length > 0) {
            const mainCompany = Options.value.userCompanyList.find(c => c.isMain === '1') || Options.value.userCompanyList[0]
            formData.myCstId = mainCompany.companyId
            formData.myCstName = mainCompany.companyName
        }
        
        dialogVisible.value = true
    }

    const getCstSelect = async (inputData = '', isPage = false) => {
        if (isPage && !Options.value.allCst.hasMore) return
        if (Options.value.allCst.isLoading) return
        await Options.value.allCst.loadNextPage(inputData, isPage)
    }

    const handleEdit = async () => {
        if (!listShow.value) {
            ElMessage.warning('请先选中一条数据！')
            return
        }
        if (!listRef.value?.isInited) {
            ElMessage.warning('列表组件初始化中，请稍后重试')
            return
        }

        try {
            listRef.value?.setLoading(true)
            const res = await request.get('/wasteBill/getDetail', { params: { id: listShow.value.id } })
            if (res.code !== 200) {
                ElMessage.error(res.msg || '接口异常')
                return
            }
            const data = res.data.bill
            const itemList = res.data.itemList || []
            
            // 判断是废品账单还是其他账单
            if (data.billType === 'waste' || !data.billType) {
                billMode.value = 'waste'
                // 先加载物品列表
                if (data.myCstId) {
                    await loadRecycleItemsByCompany(data.myCstId)
                }
                
                Object.assign(formData, JSON.parse(JSON.stringify(FORM_DEFAULT_WASTE)))
                formData.id = data.id || ''
                formData.serialNo = data.serialNo || ''
                formData.serialDate = data.serialDate
                formData.inoutType = data.inoutType
                formData.amount = data.amount
                formData.totalWeight = data.totalWeight
                formData.status = data.status
                formData.remark = data.remark || ''
                formData.myCstId = data.myCstId || ''
                formData.myCstName = data.myCstName || ''
                formData.cstId = data.cstId || ''
                formData.cstName = data.cstName || ''
                formData.cstPhone = data.cstPhone || ''
                formData.itemList = itemList.map(item => ({
                    itemId: item.itemId,
                    itemName: item.itemName,
                    price: item.price,
                    weight: item.weight,
                    amount: item.amount
                }))
            } else {
                billMode.value = 'other'
                Object.assign(formData, JSON.parse(JSON.stringify(FORM_DEFAULT_OTHER)))
                formData.id = data.id || ''
                formData.serialNo = data.serialNo || ''
                formData.serialDate = data.serialDate
                formData.inoutType = data.inoutType
                formData.amount = data.amount
                formData.usageQuantity = data.usageQuantity
                formData.billType = data.billType
                formData.status = data.status
                formData.remark = data.remark || ''
                formData.myCstId = data.myCstId || ''
                formData.myCstName = data.myCstName || ''
                formData.cstId = data.cstId || ''
                formData.cstName = data.cstName || ''
                formData.cstPhone = data.cstPhone || ''
            }

            if (!Options.value.allCst?.cstList.length > 0) {
                await getCstSelect(formData.cstId, false)
            }

            dialogType.value = 'edit'
            dialogVisible.value = true
        } catch (error) {
            ElMessage.error('获取详情失败：' + error)
        } finally {
            listRef.value?.setLoading(false)
        }
    }

    const handleDelete = async () => {
        if (!oneShow.value) {
            ElMessage.warning('请先选中数据！')
            return
        }
        // 检查状态，状态为1或2时不能删除
        const status = oneShow.value.status
        if (status === '1' || status === '2') {
            ElMessage.warning('状态为未结算或已结算时不能删除')
            return
        }
        try {
            await ElMessageBox.confirm(
                '确定删除选中的数据？',
                '删除确认',
                { confirmButtonText: '确定', cancelButtonText: '取消', type: 'warning' }
            )

            listRef.value?.setLoading(true)
            const params = {
                id: listShow.value.id
            }
            const res = await request.post('/wasteBill/del', params)
            if (listRef.value) {
                if (res.code === 200) {
                    ElMessage.success('删除成功')
                    const pagination = listRef.value.getPagination()
                    handleLoadList(pagination)
                } else {
                    MsgBox.warning2('删除失败：' + (res.msg || '接口异常'))
                }
            }
        } catch (error) {
            if (error !== 'cancel') {
                ElMessage.error('删除失败：网络异常')
            }
        } finally {
            listRef.value?.setLoading(false)
        }
    }

    const handleSubmit = async () => {
        if (!formRef.value) return

        if (isWasteMode.value) {
            if (formData.itemList.length === 0) {
                ElMessage.warning('请至少选择一个物品')
                return
            }
            const invalidItem = formData.itemList.find(item => !item.weight || parseFloat(item.weight) <= 0)
            if (invalidItem) {
                ElMessage.warning(`请填写物品【${invalidItem.itemName}】的重量（必须大于0）`)
                return
            }
        }

        const isValid = await new Promise((resolve) => {
            formRef.value.validate((valid) => {
                resolve(valid)
            })
        })
        if (!isValid) return

        let submitData
        if (isWasteMode.value) {
            submitData = {
                id: dialogType.value === 'edit' ? formData.id : '',
                serialDate: formData.serialDate,
                inoutType: formData.inoutType,
                amount: parseFloat(formData.amount),
                status: formData.status,
                remark: formData.remark,
                myCstId: formData.myCstId,
                myCstName: formData.myCstName,
                cstId: formData.cstId,
                cstName: formData.cstName,
                billType: 'waste',
                itemList: formData.itemList.filter(item => item.weight && parseFloat(item.weight) > 0).map(item => ({
                    ...item,
                    weight: parseFloat(item.weight),
                    price: parseFloat(item.price),
                    amount: parseFloat(item.amount)
                }))
            }
        } else {
            submitData = {
                id: dialogType.value === 'edit' ? formData.id : '',
                serialDate: formData.serialDate,
                inoutType: formData.inoutType,
                amount: parseFloat(formData.amount),
                status: formData.status,
                remark: formData.remark,
                myCstId: formData.myCstId,
                myCstName: formData.myCstName,
                cstId: formData.cstId,
                cstName: formData.cstName,
                billType: formData.billType,
                usageQuantity: currentBillType.value?.needUsage ? parseFloat(formData.usageQuantity) : null
            }
        }

        if (dialogType.value === 'edit') {
            submitData.serialNo = formData.serialNo
        }

        listRef.value?.setLoading(true)
        try {
            const res = await request.post('/wasteBill/saveOrUpdate', submitData)
            if (listRef.value) {
                if (res.code === 200) {
                    ElMessage.success(dialogType.value === 'add' ? '新增成功' : '修改成功')
                    dialogVisible.value = false
                    const pagination = listRef.value.getPagination()
                    handleLoadList(pagination)
                } else {
                    const tip = dialogType.value === 'add' ? '新增失败' : '修改失败'
                    ElMessage.error(tip + '：' + (res.msg || '接口异常'))
                }
            }
        } catch (error) {
            ElMessage.error('接口异常：' + error)
        } finally {
            listRef.value?.setLoading(false)
        }
    }

    const initData = async () => {
        const [inoutTypeRes, companyListRes] = await Promise.allSettled([
            enumSelect('enumType', 'in_out').catch(() => []),
            request.get('/home/getCompanyList', { params: { companyType: 'company_type_fpz' } }).catch(() => ({ code: -1 }))
        ])

        if (inoutTypeRes.status === 'fulfilled') {
            Options.value.inoutType = inoutTypeRes.value
        }
        if (companyListRes.status === 'fulfilled' && companyListRes.value.code === 200) {
            Options.value.userCompanyList = companyListRes.value.data || []
        }
    }

    onMounted(async () => {
        await nextTick()
        await initData()
        setTimeout(() => {
            if (listRef.value?.isInited) {
                const pagination = listRef.value.getPagination()
                handleLoadList(pagination)
            }
        }, 50)
    })

    onActivated(async () => {
        await initData()
        if (listRef.value?.isInited) {
            const pagination = listRef.value.getPagination()
            handleLoadList(pagination)
        }
    })

    return {
        searchForm,
        listRef,
        dialogType,
        formRef,
        oneShow,
        listShow,
        formData,
        formRules,
        Plus, Edit, Delete,
        handleSelectionChange,
        handleCurrentRowChange,
        handleAdd,
        handleAddOther,
        handleEdit,
        handleDelete,
        handleSubmit,
        handleLoadList,
        handleReset,
        dialogVisible,
        Options,
        getCstSelect,
        checkedItemIds,
        handleItemCheckChange,
        calculateTotalAmount,
        handleCompanyChange,
        isWasteMode,
        currentBillType
    }
}
